package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetIgnoreSurroundingSpaces() throws Exception {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Set the value of ignoreSurroundingSpaces to true
        when(csvFormat.getIgnoreSurroundingSpaces()).thenReturn(true);

        // Verify the value returned by getIgnoreSurroundingSpaces method
        assertEquals(true, csvFormat.getIgnoreSurroundingSpaces());
    }
}
